CREATE TABLE IF NOT EXISTS pmo_meeting_invitees (invitee_id BIGSERIAL PRIMARY KEY, meeting_id UUID REFERENCES pmo_meetings(meeting_id) ON DELETE CASCADE, name TEXT NOT NULL, role TEXT, reason TEXT, email TEXT, discord_id TEXT, is_client BOOLEAN NOT NULL DEFAULT FALSE, attendance_status TEXT NOT NULL DEFAULT 'invited', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE(meeting_id, name));

ALTER TABLE pmo_meeting_invitees ADD COLUMN IF NOT EXISTS is_client BOOLEAN NOT NULL DEFAULT FALSE;
ALTER TABLE pmo_meeting_invitees ADD COLUMN IF NOT EXISTS attendance_status TEXT NOT NULL DEFAULT 'invited';
CREATE TABLE IF NOT EXISTS pmo_meeting_reminders (reminder_id BIGSERIAL PRIMARY KEY, meeting_id UUID REFERENCES pmo_meetings(meeting_id) ON DELETE CASCADE, reminder_type TEXT NOT NULL, scheduled_at TIMESTAMPTZ NOT NULL, status TEXT NOT NULL DEFAULT 'pending', payload JSONB NOT NULL DEFAULT '{}'::jsonb, queued_at TIMESTAMPTZ, sent_at TIMESTAMPTZ, last_error TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE(meeting_id, reminder_type));
CREATE TABLE IF NOT EXISTS pmo_meeting_logs (log_id BIGSERIAL PRIMARY KEY, meeting_id UUID REFERENCES pmo_meetings(meeting_id) ON DELETE SET NULL, correlation_id TEXT, action TEXT NOT NULL, actor TEXT, details JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
SELECT
  json_build_object(
    'scheduled', (SELECT COUNT(*) FROM pmo_meetings WHERE status IN ('scheduled','confirmed')),
    'needs_reschedule', (SELECT COUNT(*) FROM pmo_meetings WHERE status = 'needs_reschedule'),
    'today', (SELECT COUNT(*) FROM pmo_meetings WHERE status IN ('scheduled','confirmed') AND (scheduled_for AT TIME ZONE 'America/Guayaquil')::date = (NOW() AT TIME ZONE 'America/Guayaquil')::date),
    'week', (SELECT COUNT(*) FROM pmo_meetings WHERE status IN ('scheduled','confirmed') AND scheduled_for BETWEEN NOW() AND NOW() + INTERVAL '7 days')
  ) AS stats,
  COALESCE((SELECT json_agg(t) FROM (
    SELECT m.*, COALESCE((SELECT json_agg(i) FROM (SELECT name, role, reason, is_client, attendance_status FROM pmo_meeting_invitees WHERE meeting_id = m.meeting_id ORDER BY is_client DESC, name) i), '[]'::json) AS invitees,
      COALESCE((SELECT json_agg(r) FROM (SELECT reminder_type, scheduled_at, status FROM pmo_meeting_reminders WHERE meeting_id = m.meeting_id ORDER BY scheduled_at) r), '[]'::json) AS reminders
    FROM pmo_meetings m
    WHERE COALESCE(m.scheduled_for, m.created_at) >= NOW() - INTERVAL '2 days'
    ORDER BY COALESCE(m.scheduled_for, m.created_at) ASC
    LIMIT 80
  ) t), '[]'::json) AS meetings,
  COALESCE((SELECT json_agg(t) FROM (SELECT log_id, meeting_id, action, actor, details, created_at FROM pmo_meeting_logs ORDER BY created_at DESC LIMIT 40) t), '[]'::json) AS logs;

