const parseArr = (v) => Array.isArray(v) ? v : (typeof v === 'string' ? JSON.parse(v || '[]') : []);
const parseObj = (v) => v && typeof v === 'object' && !Array.isArray(v) ? v : (typeof v === 'string' ? JSON.parse(v || '{}') : {});
const stats = parseObj($json.stats);
const meetings = parseArr($json.meetings);
const logs = parseArr($json.logs);
const token = String($('Webhook - Calendar').first().json.query?.token || '');
const focus = String($('Webhook - Calendar').first().json.query?.focus || '');
const esc = (v) => String(v ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
const fmt = (v) => v ? new Date(v).toLocaleString('es-EC', { timeZone:'America/Guayaquil', dateStyle:'medium', timeStyle:'short' }) : 'Sin horario';
const day = (v) => v ? new Date(v).toLocaleDateString('es-EC', { timeZone:'America/Guayaquil', weekday:'long', month:'short', day:'numeric' }) : 'Sin horario';
const parseInvitees = (m) => parseArr(m.invitees);
const badge = (s) => {
  const v = String(s || 'scheduled').toLowerCase();
  const cls = ['cancelled','needs_reschedule'].includes(v) ? 'bad' : ['scheduled','proposed'].includes(v) ? 'warn' : 'ok';
  return `<span class='badge ${cls}'>${esc(v)}</span>`;
};
const groups = new Map();
for (const m of meetings) {
  const key = day(m.scheduled_for || m.created_at);
  if (!groups.has(key)) groups.set(key, []);
  groups.get(key).push(m);
}
const meetingCards = [...groups.entries()].map(([label, items]) => `
  <section class='day'><h2>${esc(label)}</h2>${items.map((m) => {
    const invitees = parseInvitees(m);
    const highlighted = focus && (String(m.idempotency_key) === focus || String(m.meeting_id) === focus);
    return `<article class='meeting ${highlighted ? 'focus' : ''}' data-search='${esc(JSON.stringify(m).toLowerCase())}'>
      <div class='meeting-top'><div>${badge(m.status)} <span class='priority'>${esc(m.priority || 'medium')}</span></div><code>${esc(String(m.meeting_id).slice(0,8))}</code></div>
      <h3>${esc(m.title)}</h3>
      <p>${esc(m.objective || m.context_summary || '-')}</p>
      <div class='meta'><span>${esc(fmt(m.scheduled_for))}</span><span>${esc(m.duration_minutes || 30)} min</span><span>${esc(m.scheduling_status || '')}</span></div>
      ${m.scheduling_notes ? `<div class='note'>${esc(m.scheduling_notes)}</div>` : ''}
      <div class='invitees'>${invitees.map(i => `<span>${esc(i.name)}${i.is_client ? ' · cliente' : ''}</span>`).join('')}</div>
      <div class='actions'>
        <button onclick="act('${esc(m.meeting_id)}','confirm')">Confirmar</button>
        <button onclick="act('${esc(m.meeting_id)}','done')">Finalizar</button>
        <button class='danger' onclick="act('${esc(m.meeting_id)}','cancel')">Cancelar</button>
      </div>
    </article>`;
  }).join('')}</section>`).join('');
const logRows = logs.length ? logs.map(l => `<tr><td>${esc(fmt(l.created_at))}</td><td>${esc(l.action)}</td><td>${esc(l.actor || '-')}</td><td><code>${esc(String(l.meeting_id || '').slice(0,8))}</code></td></tr>`).join('') : `<tr><td colspan='4' class='empty'>Sin logs recientes.</td></tr>`;
const html = `<!doctype html><html lang='es'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>PetSafe PM Calendar</title><style>
:root{--bg:#0d1421;--panel:#141f31;--line:rgba(148,163,184,.18);--text:#eef4ff;--muted:#94a3b8;--ok:#22c55e;--warn:#f59e0b;--bad:#ef4444;--accent:#60a5fa}*{box-sizing:border-box}body{margin:0;font-family:Inter,system-ui,Arial,sans-serif;background:linear-gradient(135deg,#0d1421,#111827 60%,#18243a);color:var(--text)}.shell{width:min(1180px,calc(100% - 28px));margin:24px auto 48px}.hero{border:1px solid var(--line);border-radius:26px;background:rgba(20,31,49,.88);padding:28px;box-shadow:0 24px 70px rgba(0,0,0,.34)}h1{font-size:clamp(2rem,4vw,3rem);margin:0 0 8px}p{color:var(--muted);line-height:1.55}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-top:20px}.stat{border:1px solid var(--line);border-radius:18px;padding:16px;background:rgba(255,255,255,.035)}.stat span{display:block;color:var(--muted);font-size:.72rem;text-transform:uppercase;letter-spacing:.08em}.stat strong{font-size:1.8rem}.toolbar{display:flex;gap:10px;margin:18px 0}.toolbar input{flex:1;background:#0b1220;border:1px solid var(--line);border-radius:14px;color:var(--text);padding:12px}.calendar{display:grid;grid-template-columns:1fr;gap:18px}.day{border:1px solid var(--line);border-radius:22px;background:rgba(20,31,49,.72);padding:18px}.day h2{margin:0 0 14px;text-transform:capitalize}.meeting{border:1px solid var(--line);border-radius:18px;background:rgba(8,13,22,.44);padding:16px;margin:12px 0}.meeting.focus{outline:2px solid var(--accent)}.meeting-top{display:flex;justify-content:space-between;gap:12px;align-items:center}.badge{display:inline-flex;border-radius:999px;padding:5px 9px;font-size:.72rem;font-weight:800}.badge.ok{background:rgba(34,197,94,.14);color:#bbf7d0}.badge.warn{background:rgba(245,158,11,.14);color:#fde68a}.badge.bad{background:rgba(239,68,68,.14);color:#fecaca}.priority{color:var(--muted);font-size:.8rem;margin-left:8px}h3{font-size:1.12rem;margin:12px 0 6px}.meta,.invitees{display:flex;flex-wrap:wrap;gap:8px;margin-top:12px}.meta span,.invitees span{border:1px solid rgba(148,163,184,.14);border-radius:999px;background:rgba(255,255,255,.04);padding:7px 10px;color:#cbd5e1;font-size:.82rem}.note{margin-top:10px;color:#fed7aa}.actions{display:flex;flex-wrap:wrap;gap:8px;margin-top:14px}button{border:0;border-radius:12px;padding:9px 12px;background:#2563eb;color:white;font-weight:800;cursor:pointer}.danger{background:#7f1d1d}.logs{margin-top:20px;border:1px solid var(--line);border-radius:22px;overflow:hidden;background:rgba(20,31,49,.72)}table{width:100%;border-collapse:collapse}th,td{padding:12px;border-bottom:1px solid rgba(148,163,184,.1);text-align:left}th{color:var(--muted);font-size:.72rem;text-transform:uppercase;letter-spacing:.08em}.empty{text-align:center;color:var(--muted)}.hide{display:none}@media(max-width:760px){.stats{grid-template-columns:1fr}.actions button{width:100%}}</style></head><body><div class='shell'>
<section class='hero'><h1>PetSafe PM Calendar</h1><p>Calendario PMO interno. Evita choques por invitado, agenda en horas prudentes y mantiene recordatorios por Discord sin depender de Google Calendar u Outlook.</p><div class='stats'>
<div class='stat'><span>Agendadas</span><strong>${Number(stats.scheduled||0)}</strong></div><div class='stat'><span>Hoy</span><strong>${Number(stats.today||0)}</strong></div><div class='stat'><span>7 dias</span><strong>${Number(stats.week||0)}</strong></div><div class='stat'><span>Replanificar</span><strong>${Number(stats.needs_reschedule||0)}</strong></div>
</div></section><div class='toolbar'><input placeholder='Filtrar por titulo, invitado, estado...' oninput='filterRows(this.value)'></div><main class='calendar'>${meetingCards || `<section class='day'><p class='empty'>No hay reuniones próximas.</p></section>`}</main>
<section class='logs'><table><thead><tr><th>Fecha</th><th>Accion</th><th>Actor</th><th>Meeting</th></tr></thead><tbody>${logRows}</tbody></table></section>
</div><script>
const token=${JSON.stringify(token)} || new URLSearchParams(location.search).get('token') || '';
function filterRows(q){q=(q||'').toLowerCase();document.querySelectorAll('.meeting[data-search]').forEach(el=>el.classList.toggle('hide',q&&!el.dataset.search.includes(q)));}
async function act(id, action){
  const res=await fetch('/webhook/pm-calendar-action',{method:'POST',headers:{'Content-Type':'application/json','x-pm-token':token},body:JSON.stringify({meeting_id:id,action,token})});
  if(!res.ok){ alert('No se pudo actualizar la reunion'); return; }
  location.reload();
}
</script></body></html>`;
return [{ json: { html } }];

