CREATE TABLE IF NOT EXISTS pmo_meeting_logs (log_id BIGSERIAL PRIMARY KEY, meeting_id UUID, correlation_id TEXT, action TEXT NOT NULL, actor TEXT, details JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS events_outbox (outbox_id BIGSERIAL PRIMARY KEY, event_id TEXT, target TEXT NOT NULL DEFAULT 'discord', action TEXT NOT NULL DEFAULT 'notify', idempotency_key TEXT, payload JSONB NOT NULL DEFAULT '{}'::jsonb, status TEXT NOT NULL DEFAULT 'pending', retry_count INTEGER NOT NULL DEFAULT 0, scheduled_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), sent_at TIMESTAMPTZ, last_error TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE UNIQUE INDEX IF NOT EXISTS events_outbox_idempotency_key_uq ON events_outbox (idempotency_key);
WITH input AS (
  SELECT $1::uuid AS meeting_id, lower($2::text) AS action, COALESCE($3::text, 'pm_bot') AS actor
), updated AS (
  UPDATE pmo_meetings m
  SET status = CASE input.action WHEN 'confirm' THEN 'confirmed' WHEN 'cancel' THEN 'cancelled' WHEN 'done' THEN 'done' ELSE m.status END,
      updated_at = NOW()
  FROM input
  WHERE m.meeting_id = input.meeting_id
    AND input.action IN ('confirm','cancel','done')
  RETURNING m.*, input.action, input.actor
), log_row AS (
  INSERT INTO pmo_meeting_logs (meeting_id, correlation_id, action, actor, details)
  SELECT meeting_id, correlation_id, 'calendar_' || action, actor, jsonb_build_object('status', status, 'title', title, 'scheduled_for', scheduled_for)
  FROM updated
), outbox AS (
  INSERT INTO events_outbox (event_id, target, action, idempotency_key, payload)
  SELECT correlation_id, 'discord', 'notify', 'calendar-action:' || meeting_id || ':' || action,
    jsonb_build_object('content', '**Calendario PMO actualizado**\n' || title || '\nEstado: ' || status || '\nID: `' || meeting_id || '`')
  FROM updated
  ON CONFLICT (idempotency_key) DO NOTHING
)
SELECT true AS ok, meeting_id, title, status, scheduled_for, action, NULL::text AS error FROM updated
UNION ALL
SELECT false AS ok, $1::uuid AS meeting_id, NULL::text AS title, NULL::text AS status, NULL::timestamptz AS scheduled_for, lower($2::text) AS action, 'meeting_not_found_or_invalid_action' AS error
WHERE NOT EXISTS (SELECT 1 FROM updated);
